  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France (merging into a combined entity with Wingify/VWO as of a January 2026 deal)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AB Tasty Review 2026: Pricing, Features and Wingify Merger$q$, seo_title),
  seo_meta_description = COALESCE($q$See what AB Tasty offers for A/B testing, personalization, and feature flagging, plus pricing guidance and details on its 2026 merger with Wingify's VWO.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AB Tasty is a digital experience optimization platform founded in 2009 in Paris, France, by Alix de Sagazan and Remi Aubert. The platform is used by enterprise marketing, product, and engineering teams to run A/B and multivariate tests, personalize website and app experiences, manage feature flags, and progressively roll out product changes, with the stated goal of reducing risk in digital changes, accelerating experimentation cycles, and reducing dependency on engineering resources through no-code and low-code testing tools. AB Tasty's platform spans web experimentation, personalization, feature experimentation and flagging, and product analytics, positioning it as a broader digital experience optimization suite rather than a narrow A/B testing point solution. In a major industry consolidation, private equity firm Everstone Capital announced in January 2026 that it was merging AB Tasty with Wingify, the India-based parent company of the competing experimentation platform VWO, which Everstone had acquired a majority stake in during January 2025. The combined entity, valued in the reported range of 400 to 500 million USD, is expected to serve more than 4,000 customers globally, generate more than 100 million USD in annual revenue, and employ close to 800 people across 11 offices spanning North America, Latin America, Europe, and Asia-Pacific. Wingify co-founder Sparsh Gupta was named CEO of the merged company, with Wingify co-founder Ankit Jain serving as chief product and technology officer and AB Tasty's co-founders taking senior roles in the combined organization. Prior to the merger, AB Tasty's pricing was entirely custom and quote-based, calculated using traffic bands and monthly active user levels rather than public flat-rate tiers, with reported starting costs in the tens of thousands of dollars per year for enterprise deployments and full-platform contracts reported to exceed 60,000 USD annually. Because AB Tasty is targeted at enterprise brands running high-traffic websites and apps, its customer base has skewed toward larger organizations with dedicated conversion rate optimization, product, or growth teams rather than small businesses or solo marketers, a segment more commonly served by lower-cost self-serve competitors. Following the merger, prospective buyers evaluating AB Tasty should expect that pricing, product roadmap, and support structures may evolve as the platform integrates with Wingify's VWO under shared ownership and leadership.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eaff9b0a-92d0-49bc-91fb-3894c0e5779b';

